// Normalize all trigger payloads into { topic, content, privacyOverride }.
// Manual / Schedule -> empty topic (random idea).
// Webhook POST body -> { topic, content, privacy }.
// Form Trigger -> fields placed on $json by their labels (Topic, Content, Privacy).
const item = $input.first().json || {};
const body = item.body || {};
const query = item.query || {};
const params = item.params || {};
const topic = String(
  body.topic || query.topic || params.topic ||
  item.Topic || item.topic || ''
).trim();
const content = String(
  body.content || query.content || params.content ||
  item.Content || item.content || ''
).trim();
const privacy = String(
  body.privacy || query.privacy ||
  item.Privacy || item.privacy || ''
).trim().toLowerCase();
const allowedPrivacy = ['public', 'unlisted', 'private'];
return [{
  json: {
    topic,
    content,
    privacyOverride: allowedPrivacy.includes(privacy) ? privacy : ''
  }
}];

const fs = require('fs');
const cfg = $input.first().json;
['audio','clips','subs','output'].forEach(d => fs.mkdirSync(`${cfg.workspace}/${d}`, { recursive: true }));
fs.mkdirSync(cfg.libraryDir, { recursive: true });
return [{ json: { ...cfg, initialized: true } }];

const fs = require('fs');
const path = require('path');
const cfg = $('Set Config').first().json;
const raw = $input.first().json;
const content = raw.choices?.[0]?.message?.content || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch (e) {
  throw new Error('Model did not return valid JSON: ' + content.slice(0, 200));
}
const idea = parsed.idea || 'Untitled';
const script = (parsed.script || '').trim();
const lines = Array.isArray(parsed.lines) && parsed.lines.length ? parsed.lines : script.split(/(?<=[.!?])\s+/).filter(Boolean);
const searchTerms = Array.isArray(parsed.search_terms) && parsed.search_terms.length ? parsed.search_terms : ['indian', 'city', 'people'];
// StreamElements TTS caps around 600 chars — guard.
const safeScript = script.length > 580 ? script.slice(0, 580) : script;
fs.writeFileSync(path.join(cfg.workspace, 'script.txt'), script);
fs.writeFileSync(path.join(cfg.workspace, 'idea.txt'), idea);
return [{ json: { idea, script: safeScript, fullScript: script, lines, searchTerms } }];

const fs = require('fs');
const https = require('https');
const cfg = $('Set Config').first().json;
const script = ($input.first().json.script || '').trim();
if (!script) throw new Error('No script to synthesize');
const apiKey = cfg.openaiKey;
if (!apiKey) throw new Error('OPENAI_API_KEY missing — Set Config did not resolve $env.OPENAI_API_KEY');
const dest = `${cfg.workspace}/audio/voice.mp3`;
const body = JSON.stringify({ model: 'tts-1', voice: cfg.ttsVoice || 'nova', input: script, response_format: 'mp3' });
await new Promise((resolve, reject) => {
  const req = https.request({
    method: 'POST',
    hostname: 'api.openai.com',
    path: '/v1/audio/speech',
    headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) }
  }, (res) => {
    if (res.statusCode !== 200) {
      let err = '';
      res.on('data', c => err += c);
      res.on('end', () => reject(new Error(`OpenAI TTS HTTP ${res.statusCode}: ${err.slice(0,500)}`)));
      return;
    }
    const file = fs.createWriteStream(dest);
    res.pipe(file);
    file.on('finish', () => file.close(() => resolve()));
    file.on('error', reject);
  });
  req.on('error', reject);
  req.write(body);
  req.end();
});
const stat = fs.statSync(dest);
if (stat.size < 1000) throw new Error('Generated mp3 is too small (' + stat.size + ' bytes)');
return [{ json: { audioPath: dest, sizeBytes: stat.size, voice: cfg.ttsVoice || 'nova' } }];

const { execSync } = require('child_process');
const cfg = $('Set Config').first().json;
const out = execSync(`ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 ${cfg.workspace}/audio/voice.mp3`).toString().trim();
return [{ json: { stdout: out, duration: parseFloat(out) } }];

// Get vertical stock clips. Tries Pexels first (cfg.pexelsKey from $env), then Pixabay (cfg.pixabayKey from $env).
const https = require('https');
const cfg = $('Set Config').first().json;
const terms = ($('Parse Script').first().json.searchTerms || []).slice(0,3).join(' ') || cfg.pexelsQueryFallback;
const getJson = (opts) => new Promise((resolve, reject) => {
  https.get(opts, (res) => {
    let data = '';
    res.on('data', (c) => data += c);
    res.on('end', () => { try { resolve({ status: res.statusCode, body: JSON.parse(data) }); } catch (e) { resolve({ status: res.statusCode, body: null, raw: data.slice(0,300) }); } });
  }).on('error', reject);
});
const urls = [];
const sources = [];
const pexKey = cfg.pexelsKey;
if (pexKey) {
  try {
    const r = await getJson({
      hostname: 'api.pexels.com',
      path: `/videos/search?query=${encodeURIComponent(terms)}&orientation=portrait&size=medium&per_page=6`,
      headers: { 'Authorization': pexKey }
    });
    if (r.status === 200 && r.body && r.body.videos) {
      for (const v of r.body.videos.slice(0, 6)) {
        const candidates = (v.video_files || []).filter(f => f.file_type === 'video/mp4');
        const portrait = candidates.find(f => (f.height || 0) >= (f.width || 0));
        const file = portrait || candidates.find(f => f.quality === 'hd') || candidates[0];
        if (file) { urls.push(file.link); sources.push('pexels'); }
        if (urls.length >= 4) break;
      }
    }
  } catch (e) { /* fall through to Pixabay */ }
}
if (urls.length < 2 && cfg.pixabayKey) {
  try {
    const r = await getJson({
      hostname: 'pixabay.com',
      path: `/api/videos/?key=${cfg.pixabayKey}&q=${encodeURIComponent(terms)}&video_type=film&safesearch=true&per_page=10`
    });
    if (r.status === 200 && r.body && r.body.hits) {
      for (const hit of r.body.hits) {
        const v = hit.videos || {};
        const variants = ['large','medium','small','tiny'].map(k => v[k]).filter(Boolean);
        const portrait = variants.find(x => (x.height || 0) >= (x.width || 0));
        const pick = portrait || variants[0];
        if (pick && pick.url) { urls.push(pick.url); sources.push('pixabay'); }
        if (urls.length >= 4) break;
      }
    }
  } catch (e) { /* swallow — fallback to placeholder downstream */ }
}
// If no stock source produced clips, return empty array; Download node will create a placeholder.
return [{ json: { clipUrls: urls.slice(0, 4), sources: sources.slice(0, 4), terms, fallback: urls.length === 0 } }];

const fs = require('fs');
const path = require('path');
const https = require('https');
const http = require('http');
const { execSync } = require('child_process');
const cfg = $('Set Config').first().json;
const urls = $input.first().json.clipUrls || [];
const download = (url, dest, depth = 0) => new Promise((resolve, reject) => {
  if (depth > 5) return reject(new Error('Too many redirects'));
  const lib = url.startsWith('https') ? https : http;
  const file = fs.createWriteStream(dest);
  lib.get(url, (res) => {
    if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
      file.close(); fs.unlink(dest, () => {});
      return download(res.headers.location, dest, depth + 1).then(resolve, reject);
    }
    if (res.statusCode >= 400) {
      file.close(); fs.unlink(dest, () => {});
      return reject(new Error('HTTP ' + res.statusCode + ' for ' + url));
    }
    res.pipe(file);
    file.on('finish', () => file.close(resolve));
  }).on('error', (err) => { fs.unlink(dest, () => reject(err)); });
});
const saved = [];
for (let i = 0; i < urls.length; i++) {
  try {
    const out = path.join(cfg.workspace, 'clips', `clip_${String(i).padStart(2,'0')}.mp4`);
    await download(urls[i], out);
    saved.push(out);
  } catch (e) { /* skip bad URL, continue */ }
}
if (!saved.length) {
  // Fallback: synthesize a colored background clip with ffmpeg
  const dur = parseFloat($('Get Audio Duration').first().json.duration) || 30;
  const placeholder = path.join(cfg.workspace, 'clips', 'clip_00.mp4');
  const palette = ['0x1a1a2e','0x16213e','0x0f3460','0x533483','0x2d2d44'];
  const color = palette[Math.floor(Math.random()*palette.length)];
  execSync(`ffmpeg -y -f lavfi -i "color=c=${color}:s=1080x1920:d=${dur}" -c:v libx264 -preset veryfast -pix_fmt yuv420p "${placeholder}"`, { shell: '/bin/bash', maxBuffer: 50*1024*1024 });
  saved.push(placeholder);
}
return [{ json: { clipPaths: saved, count: saved.length, fallback: !urls.length } }];

const fs = require('fs');
const path = require('path');
const cfg = $('Set Config').first().json;
const lines = $('Parse Script').first().json.lines;
const durRaw = $('Get Audio Duration').first().json.stdout || $('Get Audio Duration').first().json;
const total = parseFloat(typeof durRaw === 'string' ? durRaw : durRaw.stdout) || 30;
const per = total / lines.length;
const pad = (n) => String(Math.floor(n)).padStart(2, '0');
const fmt = (t) => {
  const h = Math.floor(t / 3600);
  const m = Math.floor((t % 3600) / 60);
  const s = Math.floor(t % 60);
  const ms = Math.floor((t - Math.floor(t)) * 1000);
  return `${pad(h)}:${pad(m)}:${pad(s)},${String(ms).padStart(3,'0')}`;
};
let srt = '';
lines.forEach((line, i) => {
  const start = i * per;
  const end = Math.min(total, (i + 1) * per - 0.05);
  srt += `${i+1}\n${fmt(start)} --> ${fmt(end)}\n${line}\n\n`;
});
const out = path.join(cfg.workspace, 'subs', 'subs.srt');
fs.writeFileSync(out, srt);
return [{ json: { srtPath: out, totalDuration: total, lineCount: lines.length } }];

const fs = require('fs');
const { execSync } = require('child_process');
const cfg = $('Set Config').first().json;
const w = cfg.workspace;
const bgm = cfg.bgmPath;
const hasBgm = bgm && fs.existsSync(bgm);
const clips = fs.readdirSync(`${w}/clips`).filter(f => f.endsWith('.mp4')).sort();
if (!clips.length) throw new Error('No clips found in ' + w + '/clips');
fs.writeFileSync(`${w}/concat.txt`, clips.map(f => `file 'clips/${f}'`).join('\n'));
// Try to detect libass support (subtitles filter)
let hasSubFilter = false;
try {
  const filters = execSync('ffmpeg -hide_banner -filters 2>&1 | grep -E "^ [TS\\.]+ subtitles" || true', { shell: '/bin/bash' }).toString();
  hasSubFilter = filters.includes('subtitles');
} catch (e) {}
const subPart = hasSubFilter ? ",subtitles=subs/subs.srt:force_style='FontName=Arial,FontSize=20,PrimaryColour=&H00FFFFFF,OutlineColour=&H00000000,Outline=2,Shadow=1,Alignment=2,MarginV=120'" : '';
const baseFilter = `[0:v]scale=1080:1920:force_original_aspect_ratio=increase,crop=1080:1920,setsar=1${subPart}`;
let cmd;
if (hasBgm) {
  const filter = baseFilter + "[v];[1:a]volume=1.0[v1];[2:a]volume=0.12,aloop=loop=-1:size=2e9[v2];[v1][v2]amix=inputs=2:duration=first:dropout_transition=0[a]";
  cmd = `cd "${w}" && ffmpeg -y -f concat -safe 0 -i concat.txt -i audio/voice.mp3 -i "${bgm}" -filter_complex "${filter}" -map "[v]" -map "[a]" -shortest -c:v libx264 -preset veryfast -pix_fmt yuv420p -c:a aac -b:a 128k output/final.mp4`;
} else {
  const filter = baseFilter + "[v]";
  cmd = `cd "${w}" && ffmpeg -y -f concat -safe 0 -i concat.txt -i audio/voice.mp3 -filter_complex "${filter}" -map "[v]" -map 1:a -shortest -c:v libx264 -preset veryfast -pix_fmt yuv420p -c:a aac -b:a 128k output/final.mp4`;
}
execSync(cmd, { shell: '/bin/bash', maxBuffer: 200 * 1024 * 1024, stdio: ['ignore', 'pipe', 'pipe'] });
const finalPath = `${w}/output/final.mp4`;
const stat = fs.statSync(finalPath);
return [{ json: { finalPath, sizeBytes: stat.size, hasBgm, hasSubtitles: hasSubFilter, clipCount: clips.length } }];

const raw = $input.first().json;
const content = raw.choices?.[0]?.message?.content || '{}';
let meta;
try { meta = JSON.parse(content); } catch (e) {
  meta = { title: 'Funny Indian Short', description: 'Daily desi comedy short.', tags: ['shorts','comedy','indian','funny'] };
}
const tags = Array.isArray(meta.tags) ? meta.tags.map(t => String(t).replace(/^#/, '').trim()).filter(Boolean) : [];
return [{ json: { title: (meta.title || 'Funny Indian Short').slice(0, 95), description: meta.description || '', tags } }];

const fs = require('fs');
const cfg = $('Set Config').first().json;
const title = ($('Parse SEO').first().json.title || 'untitled');
const safe = title.replace(/[^A-Za-z0-9_\- ]/g, '').trim().replace(/\s+/g, '_').slice(0, 80) || 'untitled';
const dest = `${cfg.libraryDir}/${cfg.runId}-${safe}.mp4`;
fs.mkdirSync(cfg.libraryDir, { recursive: true });
fs.copyFileSync(`${cfg.workspace}/output/final.mp4`, dest);
return [{ json: { libraryPath: dest, stdout: dest } }];
